-- Import employees extracted from: اسماء_الأعضاء_العامليين_جديد_2026.docx
-- Generated for Supabase SQL Editor. Safe to re-run: rows are upserted by employee_id.
-- Total employees: 230

BEGIN;

CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pg_trgm";

ALTER TABLE public.employees ALTER COLUMN national_id DROP NOT NULL;
ALTER TABLE public.employees ALTER COLUMN email DROP NOT NULL;
ALTER TABLE public.employees ALTER COLUMN employment_date DROP NOT NULL;

ALTER TABLE public.employees ADD COLUMN IF NOT EXISTS office_code VARCHAR(50);
ALTER TABLE public.employees ADD COLUMN IF NOT EXISTS office_name VARCHAR(255);
ALTER TABLE public.employees ADD COLUMN IF NOT EXISTS office_sort_order INTEGER;
ALTER TABLE public.employees ADD COLUMN IF NOT EXISTS office_employee_order INTEGER;
ALTER TABLE public.employees ADD COLUMN IF NOT EXISTS source_document VARCHAR(255);
ALTER TABLE public.employees ADD COLUMN IF NOT EXISTS imported_at TIMESTAMP DEFAULT NOW();

CREATE INDEX IF NOT EXISTS idx_employees_office_code ON public.employees(office_code);
CREATE INDEX IF NOT EXISTS idx_employees_office_name ON public.employees(office_name);
CREATE INDEX IF NOT EXISTS idx_employees_office_order ON public.employees(office_sort_order, office_employee_order);
CREATE INDEX IF NOT EXISTS idx_employees_mobile_number ON public.employees(mobile_number);
CREATE INDEX IF NOT EXISTS idx_employees_job_title ON public.employees(job_title);

ON CONFLICT (employee_id) DO UPDATE SET
  full_name = EXCLUDED.full_name,
  mobile_number = EXCLUDED.mobile_number,
  department = EXCLUDED.department,
  office_code = EXCLUDED.office_code,
  office_name = EXCLUDED.office_name,
  job_title = EXCLUDED.job_title,
  employment_status = EXCLUDED.employment_status,
  notes = EXCLUDED.notes,
  office_sort_order = EXCLUDED.office_sort_order,
  office_employee_order = EXCLUDED.office_employee_order,
  source_document = EXCLUDED.source_document,
  imported_at = NOW(),
  updated_at = NOW(),
  deleted_at = NULL;

CREATE OR REPLACE VIEW public.active_employees AS
SELECT * FROM public.employees
WHERE deleted_at IS NULL AND employment_status = 'active'
ORDER BY office_sort_order NULLS LAST, office_employee_order NULLS LAST, full_name;

COMMIT;
